script:
function onClientStep(s) {
	if(s.kind == Steps.CheckGround) {
		if(!owner.body.grounded)
			localPlayStep(Steps.Air);
	}
}

var timeStationary = 0.0;

function onSkillProc(ctx) {
	removeBuff();
}

function onUpdate(dt) {
	if (ownerHero != null && ownerHero.gliding) {
		removeBuff();
	}
	if (Math.abs(owner.moveX) < 0.01 && Math.abs(owner.moveY) < 0.01) {
		timeStationary += dt;
	} else {
		timeStationary = 0;
	}

	if (timeStationary > vars.duration) {
		removeBuff();
	}
}

function removeBuff() {
	removeStatus(owner, status.kind);
}

function onInflictHit(hit) {
	if(hit.isFirstHit)
		ownerHero.gainSparkParticle(10);
}

function onInflictDamage(dmg) {
	if (dmg.skillId == Skill.SparkSurge_Mark)
		return;
	var amount = dmg.amount * vars.var1;
	addStatus(dmg.target, Skill.SparkSurge_Mark, amount);
}

function onStop(ctx) {
	for(s in getInflictedStatuses(Skill.SparkSurge_Mark)) {
		var count = s.consume();
	}
}

function onDamageEval(hit) {
	hit.dmgMult += status.stacks;
}

function onDamage(dmg) {
	if( dmg.critical ) {
		resetCooldown(Skill.Axe_Boomerang_Skill1);
	}
}

function onDamageEval(hit) {
	if( hit.target.hasStatusType(StatusType.Bleed) ) {
		hit.dmgMult += vars.var1;
	}
}

function onDamage(dmg) {
	var amount = dmg.amount * vars.var1;
	addStatus(dmg.target, Skill.Axe_Boomerang_Skill1_Status, amount);
}

function onDamageEval(hit) {
	if( rank >= 3 ) {
		hit.critDmgMult += vars.var2;
	}
}

function onFirstHit(hit) {
	if(rank >= 3) {
		reduceWeaponsCooldown(vars.time);
	}
}

function onDamageEval(hit) {
	if(rank >= 2) {
		hit.critChance += vars.var1;
	}
}

function onDamage(dmg) {
	if(dmg.critical && rank == 3) {
		addStatus(dmg.target, Skill.Sword_Start_Skill1Status);
	}
}

function onFirstHit(hit) {
	if( checkProba(vars.var1) ) {
		var sk = ownerHero.getDefenseWeaponSkill();
		if(sk != null) {
			sk.reduceCooldown(vars.time);
			if(rank >= 3) {
				playStep(Steps.MagicDamage, hit.target);
			}
		}
	}
}

function onGameBeat(beat, hit) {
	trace(beat);
	if( beat == GameBeat.AttackBlock) {
		resetCooldown(kind);
	}
	if(rank >= 3 && beat == GameBeat.BlockWellTimed) {
		addStatus(owner, Skill.Sword_Craft_Skill1_Status);
	}
}

function onDamageEval(hit) {
	if(rank >= 2) {
		hit.dmgMult += vars.var1;
	}
}

function onStart(ctx) {
	var stacks = consumeStatus(owner, Skill.Sword_Craft_Skill1_Status);
	if(stacks > 0) {
		ctx.dmgMult += stacks * vars.var3;
	}
}

function onRegUpdate(dt) {
	var count = countEnemiesInRange(vars.range);
	var apply = count >= vars.var1;
	var inCombat = owner.isInCombat;
	setStatus(owner, Skill.Sword_Craft_Passive_Status, apply && inCombat ? 1 : 0);
}

function onStop(ctx) {
	setStatus(owner, Skill.Sword_Craft_Passive_Status, 0);
}

function onGameBeat(beat, hit) {
	if(rank >= 3) {
		if(beat == GameBeat.BlockWellTimed) {
			playStep(Steps.HealArea);
		}
	}
}

function onUseSkill(ctx) {
	if (!owner.isInCombat) { return; }
	if (ctx.baseSkill.inf.type == WeaponSkill) {
		for (u in owner.combat) {
			var s = u.getStatus(Skill.Sword_Swam_Skill1_Status);
			if (s != null) {
				s.extendDuration(vars.time);
			}
		}
	}
}

function onUseSkill(ctx) {
	if (!owner.isInCombat) { return; }
	if (ctx.baseSkill.inf.type == WeaponSkill) {
		var stacks = vars.var1;
		if (rank >= 2) {
			stacks = vars.var2;
		}
		addStatus(owner, Skill.Sword_Swarm_Passive_Charge, stacks);
	}
}

var lastHitTime = 0.;
function onDamage(dmg) {
	if (rank >= 3) {
		if (dmg.ctx.baseSkill.time.now > lastHitTime) {
			lastHitTime = dmg.ctx.baseSkill.time.now;
			addStatus(owner, Skill.Sword_Swarm_Passive_Charge_Bonus);
		}
	}
}
function onReceiveDamage(dmg) {
	if (dmg.baseSkill?.inf.type == Attack) {
		consumeStatus(owner, Skill.Sword_Swarm_Passive_Charge, 1);
	}
}

function onFirstHit(hit) {
	if(rank >= 3) {
		reduceWeaponsCooldown(vars.time);
	}
	startSkill(Skill.Sword_Swarm_Combo_Area);
}

var record:Array<Dynamic> = [];
function onReceiveDamage(dmg) {
	if (rank >= 3) {
		record.push({time:owner.time.now, amount:dmg.amount});
	}
}

function cleanRecord() {
	for (i in 0...record.length) {
		var r = record[i];
		if (owner.time.now - r.time > vars.time) {
			record.remove(r);
			i--;
		} else {
			break;
		}
	}
}

function getRecordValue() {
	var acc = 0.;
	for (r in record) {
		acc += r.amount;
	}
	return acc;
}

function onInflictDamageEval(hit) {
	if (hit.baseSkill.inf.id == Skill.Sword_Swarm_Combo) {
		var swarmCount = getSwarmTotal();
		hit.dmgMult += swarmCount * vars.damage;
	}
}

function onInflictHealEval(hit) {
	if (hit.baseSkill.kind == Skill.Sword_Swarm_Combo_Area && rank >= 2) {
		var swarmCount = getSwarmTotal();
		hit.dmgMult += swarmCount * vars.damage;
	}

	if (rank >= 3) {
		if (hit.target == owner) {
			cleanRecord();
			var damage = getRecordValue();
			hit.amount += damage * vars.var2;
		}
	}
}

function getSwarmTotal() {
	var total = 0;
	for (u in owner.combat) {
		var haveStatus = u.getStatus(Skill.Sword_Swam_Skill1_Status) != null;
		if (haveStatus)
			total += 1;
	}
	if (owner.getStatus(Skill.Sword_Swarm_Passive_Charge) != null)
		total += 1;
	return total;
}

function onGameBeat(beat, hit) {
	if(rank >= 3 && beat == GameBeat.BlockWellTimed) {
		addStatus(owner, Skill.Shield_Start_Skill1_Status);
	}
}

function onStart(ctx) {
	var stacks = consumeStatus(owner, Skill.Shield_Start_Skill1_Status);
	if(stacks > 0) {
		ctx.dmgMult += stacks * vars.var2;
	}
}

function onGameBeat(beat, dmg) {
	if( beat == GameBeat.AttackBlock) {
		reduceCooldown(Skill.Shield_Craft_Skill1, vars.dur1);
	}
}

var STATUS_KIND = Skill.Shield_Craft_Passive_Status;

function onRegUpdate(dt) {
	if(!isInCooldown()) {
		setStatus(owner, STATUS_KIND);
	}
}

function onReceiveDamageEval(hit) {
	if(isInCooldown()) {
		hit.dmgMult -= vars.var2;
	}
}

