			var armor = getAtb(owner, Attribute.Armor);
			var dmg = armor * vars.var1;
			ctx.dmgAdd += dmg;
			removeStatus(owner, STATUS_KIND);
			consumeCooldown();
		}
	}
}*/

function onInflictDamageEval(hit) {
	if( hasStatus(owner, Skill.Shield_Craft_Passive_Status) && hit.isFinalCombo ) {
		playStep(Steps.MagicDamage, hit.target);
		removeStatus(owner, Skill.Shield_Craft_Passive_Status);
		consumeCooldown();
	}
}

function onProc(ctx) {
	removeStatus(owner, Skill.Shield_OrbitWater_S1_OrbStatus);
	setStatus(owner, Skill.Shield_OrbitWater_S1_OrbStatus, 10);
}

function onHit(hit) {
	if( hit.stepId == Steps.Orb ) {
		consumeStatus(owner, Skill.Shield_OrbitWater_S1_OrbStatus);

		if( hasStatus(owner, Skill.Shield_OrbitWater_S1_OrbStatus) ) {
			playStep(Steps.Area);
		} else {
			var ctx = playStep(Steps.LastOrbArea);
			ctx.dmgMult += 1;
		}
	}
}

function onDamage(dmg) {
	if( rank >= 3 && dmg.stepId == Steps.LastOrbArea ) {
		addStatusDuration(dmg.target, Skill.Stun, vars.dur1);
	}
}

function onGameBeat(b, hit) {
	if( b == GameBeat.AttackBlock ) {
		addWaterInfusion();
	}
}

function onInflictHit(hit) {
	if( hit.isFinalCombo ) {
		addWaterInfusion();
	}
}

function addWaterInfusion() {
	if( !hasStatus(owner, Skill.Shield_OrbitWater_P_StatusBlockBuffed) ) {
		addStatus(owner, Skill.Shield_OrbitWater_P_Status);
	}
}

function onInflictDamage(dmg) {
	if( dmg.hitCount == 1 && dmg.skillId == Skill.Shield_OrbitWater_P_StatusBlockBuffed ) {
		reduceCooldown(Skill.Shield_OrbitWater_S1, vars.dur1);
	}
}

function onStacksChange() {
	if( stacks >= maxStacks ) {
		removeStatus(owner, Skill.Shield_OrbitWater_P_Status);
		addStatus(owner, Skill.Shield_OrbitWater_P_StatusBlockBuffed);
	}

}

function onGameBeat(b,hit) {
	if( b == GameBeat.AttackBlock ) {
		playStep(Steps.Area);
		skill.stop();
	}

}

function onInflictDamage(dmg) {
	if (dmg.isFinalCombo) {
		// triggerSkill(baseSkill);
		stop();
	}
}

function onInflictDamage(dmg) {
	if(elapsedTime > 0 && (dmg.isBaseAttack || dmg.isWeaponSkill)) {
		addStatus(dmg.target, Skill.Stinger_PassiveStatus);
	}
}

function onReceiveDamage(dmg) {
	if(elapsedTime > 0 && (dmg.isBaseAttack || dmg.isWeaponSkill) ) {
		addStacks(1);
		if( hasStatus(dmg.target, Skill.Stinger_PassiveStatus) && stacks >= vars.var1 ) {
			consumeStatus(dmg.target, Skill.Stinger_PassiveStatus);
		}
	}
}

function onRegUpdate(dt) {
	if(rank >= 2) {
		var foesBuffVal = 0.;
		var enemies = getEnemiesInRange(owner, vars.range);
		foesBuffVal += enemies.length;
		setDynVal(1, foesBuffVal);
	}
}

function onInflictHit(hit) {
	if(hit.isBaseAttack) {
		var status = owner.getStatus(Skill.DA_Water_Combo_Status);
		if(status != null && status.stacks >= status.getMaxStacks() && checkProba(vars.chance)) {
			playStep(Steps.Axe);
		}
	}
}

function onInflictHit(hit) {
	if( hit.isBaseAttack) {
		if(checkProba(vars.chance)) {
			playStep(Steps.Attack, hit.target);
		}
	}
}

function onStart(app) {
	var missing = owner.maxHealth - owner.health;
	status.setShield(missing * vars.var1);
}

function onUpdate(dt) {
	if(!status.instigatorSkill.isRunning())
		stop();
}

function onInflictDamage(dmg) {
	if( dmg.isFirstHit && dmg.isBaseAttack)
		reduceCooldown(Skill.DA_Water_Skill2, vars.time);
}

function onDamageEval(hit) {
	if( rank >= 2 )
		hit.ignoreArmor = true;
}

function onKill(dmg) {
	if(rank >= 3 && dmg.skillId == Skill.DA_Water_Skill2 ) {
		var dmg = dmg.amount;
		var amount = dmg * vars.var1;
		applyHeal(owner, amount);
	}
}

function onUpdate(dt) {
	setStatus(owner, Skill.DA_Water_Passive_Status, owner.isInCombat && owner.healthRatio < vars.var1 ? 1 : 0);
	if(rank >= 3) {
		if(owner.isInCombat && owner.healthRatio < vars.var2 && !hasStatus(owner, Skill.DA_Water_Passive_Status_R3)) {
			addStatus(owner, Skill.DA_Water_Skill1_Status);
			addStatus(owner, Skill.DA_Water_Passive_Status_R3);
		}
	}
}

function onDamageEval(hit) {
	if(rank >= 2) {
		hit.dmgMult += vars.var1;
	}
}

function onDamage(hit) {
	if( rank >= 3 && hit.critical ) {
		addStatus(hit.target, Skill.Daggers_Start_Combo_Status);
	}
}

function onSkillProc(ctx) {
	if(ctx.skill.isFinalAttack())
		resetCooldown(kind);
}

function onHit(hit) {
	if(rank >= 2) {
		hit.critChance += vars.chance;
	}
}

function onSkillProc(ctx) {
	if(ctx.skill.isWeaponSkill()) {
		ctx.dmgMult += vars.var1;
		stop();
	}
}

function onInflictDamageEval(hit) {
	if (hit.baseSkill.kind == Skill.Daggers_DuplicatePoison_ComboAttack) {
		hit.dmgMult += owner.getStatusCount(Skill.Daggers_DuplicatePoison_ComboAttack_Status) * vars.var1;
		if (rank >= 3) {
			if (hasStatusMaxStacked(owner, Skill.Daggers_DuplicatePoison_ComboAttack_Status)) {
				owner.doAllSkills(s -> reduceCooldown(s.kind, vars.time));
			}
		}
		owner.consumeStatus(Skill.Daggers_DuplicatePoison_ComboAttack_Status, 1000);
	}
}

function onInflictStatus(s) {
	if(s.isDoT() && isServer) {
		trace(s.kind);
		owner.addStatus(Skill.Daggers_DuplicatePoison_ComboAttack_Status);
	}
}

function onInflictDamage(dmg) {
	if( checkProba(vars.var1) && dmg.isStatus && dmg.status.isDoT() && isServer) {
		owner.addStatus(Skill.Daggers_DuplicatePoison_ComboAttack_Status);
	}
}

var duplicating = false;
function onInflictStatusEval(ctx) {
	if (rank >= 3) {
		if (!duplicating && ctx.status.isType(StatusType.Poison) && hasStatus(ctx.status.owner, Daggers_DuplicatePoison_Skill1_Status)) {
			ctx.stackAmount += 1;
		}
	}
}

function onInflictDamage(ctx) {
	if (rank >= 3) {
		if (ctx.skillId == skill.inf.id && hasStatusMaxStacked(ctx.target, Skill.Daggers_DuplicatePoison_PassiveStatus)) {
			startSkill(Skill.Daggers_DuplicatePoison_Skill2_Area, ctx.target);
		}
	}
}

function onInflictDamage(dmg) {
	if(checkProba(vars.chance) && elapsedTime > 0 && (dmg.isBaseAttack || dmg.isWeaponSkill)) {
		var status = addStatus(dmg.target, Skill.Daggers_DuplicatePoison_PassiveStatus);
	}
}
function onUpdate(dt) {
	if (owner == null || owner.instigatedStatuses == null) { return; }
	if (rank >= 3) {
		var anyAtMaxStack = false;
		for (s in owner.instigatedStatuses) {
			if (s.kind == Skill.Daggers_DuplicatePoison_PassiveStatus) {
				if (hasStatusMaxStacked(s.owner, Skill.Daggers_DuplicatePoison_PassiveStatus)) {
					anyAtMaxStack = true;
				}
			}
		}
		var haveStatus = owner?.getStatusCount(Skill.Daggers_DuplicatePoison_Passive_Bonus) > 0;
		if (anyAtMaxStack) {
			if (!haveStatus) {
				owner.addStatus(Skill.Daggers_DuplicatePoison_Passive_Bonus);
			}
		} else {
			if (haveStatus) {
				removeStatus(owner, Skill.Daggers_DuplicatePoison_Passive_Bonus);
			}
		}
	}
}

function onInflictDamageEval(dmg) {
	if (dmg.skillId == Skill.Daggers_DuplicatePoison_PassiveStatus) {
		if (rank >= 2) {
			var otherStatusCount = 0;
			for (s in dmg.target.statuses) {
				if (s.getSourceSkill().owner == owner && s.kind != Skill.Daggers_DuplicatePoison_PassiveStatus) {
					otherStatusCount++;
				}
			}
			dmg.dmgMult += otherStatusCount * vars.var1;
		}
	}
}

function onHitNewTarget(hit) {
    addStatus(hit.target, Skill.AmaymonMartyr_Mark, vars.var1);
}

function onDamageEval(hit) {
    hit.setBeat(GameBeat.Critical);
}

function onInflictDamage(dmg) {
    if( dmg.skillId == Skill.AmaymonMartyr_Mark) {
        reduceCooldown(Skill.AmaymonMartyr_Skill_3, vars.var1);
    }
}

function onInflictDamage(dmg) {
    if( dmg.isStatusType(StatusType.Bleed) && checkProba(vars.chance)) {
        resetCooldown(Skill.AmaymonMartyr_Skill_2);
    }
}

function onInflictDamage(dmg) {
	if((dmg.isBaseAttack || dmg.isSkill) && checkProba(vars.chance)) {
		addStatus(dmg.target, Skill.AmaymonMartyr_Mark, vars.var1);
	}
}

