}

function onDamage(dmg) {
    addStacks(-1);
    if(stacks == 0)
        stop();
}

function onDamage(dmg) {
	var status = addStatus(dmg.target, Skill.HyperionsNeedle_Combo_Status);
	if( status != null )
		status.dynVal1 = dmg.amount * vars.var1;
}

function onDamageEval(hit) {
	if(hit.target.hasStatusType(StatusType.Bleed)){
		hit.dmgMult += vars.var1;
	}
}

function onKill(u) {
	if(rank >= 2)
		resetCooldown(kind);
}

var comboCount = 0;
function onStart(ctx) {
	comboCount = 0;
}

function onSkillProc(ctx) {
	if(ctx.skill.isFinalAttack() && rank >= 3) {
		comboCount++;
		if(comboCount <= 1) {
			ctx.dmgMult += vars.damage;
		}
	}
}

function onInflictHit(hit) {
	if( rank >= 3 && hit.isBaseAttack) {
		if(checkProba(vars.chance)) {
			playStep(Steps.Attack, hit.target);
		}
	}
}

function onKill(dmg) {
	if( rank >= 3 && dmg.skillId == Skill.GA_Craft_Skill1  ) {
		resetCooldown(Skill.GA_Craft_Skill2);
	}
}

function onInflictDamageEval(hit) {
	if( hit.target.hasStatusType(StatusType.Stun) || hit.target.hasStatusType(StatusType.Root) || hit.target.hasStatusType(StatusType.Slow) ) {
		hit.dmgMult += vars.var1;
	}
}

function onDamageEval(dmg) {
	if (rank >= 2 && dmg.isFirstHit) {
		dmg.dmgMult += vars.var1;
	}
	if (rank >= 3 && getStatusCount(dmg.target, Skill.HiveGreatMace_FinalCombo_Debuff) >= vars.var2) {
		dmg.dmgMult += vars.var3;
	}
}

function onInflictDamage(dmg) {
	if (dmg.isFinalCombo) {
		triggerSkill(status);
		stop();
	}
}

function onInflictDamage(dmg) {
	if (dmg.isFirstHit && (dmg.isBaseAttack || dmg.isWeaponSkill) && !hasStatus(owner, Skill.HiveGreatMace_MadBuzz_Buff)) {
		// addStatus(owner, Skill.HiveGreatMace_MadBuzz_Buzzing);
		// if (hasReachedStackLimit(owner, Skill.HiveGreatMace_MadBuzz_Buzzing)) {
		// 	addStatus(owner, Skill.HiveGreatMace_MadBuzz_Buff);
		// 	clearStatusStacks(owner, Skill.HiveGreatMace_MadBuzz_Buzzing);
		// }
	}
}

function onInflictDamage(dmg) {
	// if (isServer && (dmg.isBaseAttack || dmg.isWeaponSkill)) {
	// 	playMicroEffectsOnTarget(dmg.target);
	// }
	if (rank >= 2 && dmg.skillId == Skill.HiveGreatMace_MadBuzz_Buff && dmg.critical) {
		reduceWeaponsCooldown(vars.cooldown);
	}
}

function onDamageEval(hit) {
	if(rank >= 2) {
		hit.dmgMult += vars.var1;
	}
	if(rank >= 3) {
		if(hit.target.hasStatusType(StatusType.Burn)) {
			hit.critChance += vars.chance;
		}
	}
}

function onStart(ctx) {
	if(rank >= 2) {
		ctx.dmgMult += vars.var1;
	}
}

function onHitNewTarget(hit) {
    if( hit.target.hasStatusType(StatusType.Burn) ) {
		addStatusDuration(hit.target, Skill.Stun, vars.var1);
    }
}

function onHit(hit) {
	if(rank >= 2) {
		hit.critChance += vars.chance;
	}
}
function onDamage(dmg) {
	if(dmg.critical && rank == 3) {
		addStatusDuration(dmg.target, Skill.Stun, vars.time);
	}
}

function onHit(hit) {
	if(rank >= 2 && hit.stepId == Steps.Allies) {
		for(s in hit.target.skills) {
			if(s.isWeaponSkill() && s != skill ) {
				s.reduceCooldown(vars.time);
			}
		}
	}
}

function onStart(ctx) {
	if(rank >= 2) {
		addSkillCharges(Skill.OniricScepter_Skill1, vars.charges);
	}
	if(rank >= 3) {
		reduceWeaponsCooldown(vars.cooldown);
	}
}

function checkEnabled() {
	var area = getClosestAreaBySkill(owner, Skill.OniricScepter_Skill1_Area, owner);
	if(area == null || !isInRange(area, owner, vars.range))
		return Reason.NoDreamSphere;
	return Reason.Ok;
}

function onStart(ctx) {
	var area = getClosestAreaBySkill(owner, Skill.OniricScepter_Skill1_Area, owner);
	if(area != null && rank < 3) {
		area.remove();
	}
}

function onStart(ctx) {
	setDynVal(1, 0);
}

function onDamage(dmg) {
	setDynVal(1, dmg.amount * vars.heal);
}

function onProc(ctx) {
	for(s in getInflictedStatuses(Skill.Scepter_Flamie_Flamie)) {
		s.extendDuration(vars.dur1);
	}
}

function onDamageEval(dmg) {
	if(rank >= 2) {
		dmg.dmgMult += vars.var1;
	}
