function onOwnerWillConsumeResource(res, ctx) {
	if( res != Attribute.Spark || !isEnabled() )
		return;

    var skills = getSkillInstances();
	if(skills == null) return;

    var fanRadius = 2.5;
    var fanAmplitude = 240;
    var shotDelay = 0.1;

	var target = owner.getTarget();
    var count = 0;

    for(s in skills) {
        if(s.isEnabled())
            count += round(s.vars.var1);
    }

    if (target != null) {
        var projStep = getStepById(Steps.Projectile);
        var startPos = projStep.getProjectileStart();

        var interProgress = 1 / (count+1);
        for (i in 0...count) {
            var pos = startPos;
            if (count > 1) {
                pos = p3DAdd(startPos, getFanFacingPos((i+1) * interProgress, fanAmplitude, fanRadius, p2DTo3D( p2DSub(target.pos2D, owner.pos2D)) ) );
            }
            wait(i * shotDelay, function() {
                projStep.generateProjectile(target, pos);
            });
        }
    }
}

