function chaoticRunUpdate(dt) {
    if(!isServer || chaoticRunStartPos == null)
        return;
    if(elapsedTime > nextRunPick) {
        var runTime = random(minRunTime, maxRunTime);
        nextRunPick = elapsedTime + runTime;
        var radius = runTime * getAtb(owner, Attribute.SprintSpeed);
        var targetPos = getRandomGroundPos(owner, radius * 1.2, radius * 1.1, 1.6, 0, 360, (pos) -> p3DDist(pos, chaoticRunStartPos) < vars.range);
        owner.forceMoveTo(targetPos, true);
    }
}

