var spawnRadius = 6;
var spawnDelay = 0.2;
function onStep(s) {
    switch(s.kind) {
        case Steps.GenerateProjectiles:
            var projStep = getStepById(Steps.Projectile);
			var nb = vars.var1;
			if( owner.phase == 3 ) {
				nb = 6;
			}
			var count =  round(nb);
            var interProgress = 1 / (count);
            var pos = projStep.getProjectileStart();
            var targetsLeft = copyArray(getAITargets());
            var rotProgress = owner.rotationZ / PI;
			if( targetsLeft.length > 0 ) {
				for(i in 0...count) {
					var tPos = p3DAdd(pos, getCircleFacingPos(rotProgress + interProgress * i, spawnRadius, owner.getUp()));
					var target = findMin(targetsLeft, (t) -> p3DDist(t.position, pos));
					targetsLeft.remove(target);
					if( targetsLeft.length == 0 )
						targetsLeft = copyArray(getAITargets());

					wait(i * spawnDelay, function() {
						projStep.generateProjectile(target, tPos);
					});
				}
			}
        default:
    }
}

