function onCreateArea(area) {
    var target = aimTarget;
    var sourceEntity = ownerObject;
    var targetEntity = target;

    // Tries to rotate itself to hit another target
    var objects = getGameObjectsInRange(target, vars.var2, function(t) {
        var u = toUnit(t);
        if(u == null)
            return false;
        return t != owner && t != target && isInCombatWith(owner, t);
    });
    if(objects[0] != null) {
        sourceEntity = objects[0];
        targetEntity = target;
    }
    var dir = getDirectionToEntity(sourceEntity, targetEntity);
    var invertDir = p2DScaled(dir, -1);
    var offset = p2DTo3D( p2DScaled(dir, vars.var1) );
    area.setPosition( p3DAdd(target.position, offset) );
    var angle = dirToAngle(invertDir);
    area.rotationZ = angle;
}

